  (1469, 'Cocos Ahorro', 4, 2418, 391, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 1, '2024-01-10', 1, '1438', 'El objetivo primario de la administración del fondo es preservar el valor del patrimonio del fondo. A tal fin, el fondo invertirá en valores negociables, instrumentos financieros y otros activos financieros de renta fija –de carácter público o privado, nacionales o extranjeros.', 0),
  (1491, 'Cocos Ahorro Dólares', 3, 2418, 115, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 2, '2024-04-17', 1, '1437', 'El objetivo primario de la administración del fondo es obtener la apreciación del valor del patrimonio del fondo. A tal fin, el fondo invertirá en valores negociables, instrumentos financieros y otros activos financieros –de renta fija o variable, de carácter público o privado, nacionales o extranjeros– mencionados en este capítulo 2 (con la denominación legal equivalente que corresponda en el caso de países distintos de la República Argentina), los que se considerarán activos autorizados.', 1),
  (1635, 'Cocos Dólares Plus', 3, 2418, 115, 'Renta Fija', 'Argentina', 'Largo Plazo', NULL, 2, '2025-04-09', 1, '1436', '.', 1),
