  (1423, 'ConoSur Visus', 7, 3300, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '2023-07-27', 1, '1277', 'Maximizar rendimiento en pesos y/o cobertura/protección de activos', 1),
  (553, 'Consultatio Abierto Pymes', 6, 22, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2013-01-17', 1, '685', 'El fondo invierte en instrumentos autorizados por la CNV que permitan dar financiamiento de corto, mediano y largo plazo al segmento de Empresas Argentina medianas y PYMES. Las pautas del buen gobierno corporativo son un objetivo perseguido por el fondo en las empresas en las que invierta.', 3),
  (216, 'Consultatio Acciones Argentina', 2, 22, 65, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '1997-11-10', 1, '271', 'Invertirá primariamente en activos de renta variable argentina, utilizando cono índice de referencia el Merval Argentina.', 1),
  (493, 'Consultatio Ahorro Plus Argentina F.C.I.', 3, 22, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2011-06-07', 1, '629', 'El fondo busca ofrecer un portafolio diversificado, que invierta en instrumentos de renta fija local de corto plazo, denominados principalmente en pesos, emitidos tanto por emisores públicos como privados.', 1),
  (763, 'Consultatio Arbitraje', 5, 22, 65, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2017-08-01', 1, '968', 'El fondo invierte en activos de renta fija, renta variable y futuros, en Pesos y USD. Los activos de renta fija podrán ser Nacionales, Provinciales o Corporativos, mientras que los activos de Renta Variable podrán operar en diferentes mercados.', 2),
  (89, 'Consultatio Balance Fund', 7, 22, 65, 'Renta Mixta', 'Argentina', 'Flexible', NULL, 1, '1995-06-12', 1, '120', 'Es un fondo de Retorno Total de renta fija, y refleja la visión de la mesa de Consultatio, adaptándose a los cambios del mercado. Puede invertir en activos denominados en ARS, USD y también en futuros.', 1),
  (585, 'Consultatio Crecimiento', 3, 22, 65, 'Renta Fija', 'Global', 'Flexible', NULL, 1, '2014-02-20', 1, '713', NULL, 2),
  (281, 'Consultatio Deuda Argentina', 3, 22, 65, 'Renta Fija', 'Argentina', 'Largo Plazo', NULL, 1, '1999-08-24', 1, '365', 'El fondo tiene como objetivo superar la evolución del índice de inflación argentina.', 1),
  (566, 'Consultatio Diamante Plus', 3, 22, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2013-07-01', 1, '706', 'Consultatio Diamante Plus es un fondo de renta fija con horizonte de inversión de corto-mediano plazo. Está nominado en pesos para las suscripciones, rescates y valuación de la cartera de inversiones. El objetivo del fondo es invertir en activos que devenguen tasas en pesos con duración de hasta 1 año y procurando la preservación de capital como premisa principal.', 1),
  (648, 'Consultatio Estrategia', 3, 22, 65, 'Renta Fija', 'Global', 'Flexible', NULL, 1, '2016-02-18', 1, '780', 'El fondo invierte en instrumentos de renta fija internacionales, emitidos por gobiernos, corporaciones, instituciones supranacionales, multilaterales y cuasi-soberanos. El foco estará en emisores con mayoría en grado de inversión, relevantes para la economía mundial/regional y en posiciones cuyas historias de crédito están sólidas y en camino a una mejoría.', 1),
  (1701, 'Consultatio Estrategia I', 3, 22, 65, 'Renta Fija', 'Argentina', 'Flexible', NULL, 2, '2025-08-18', 1, '1707', 'El objetivo primario de la administración del Fondo es procurar la apreciación del valor del patrimonio del Fondo.', 2),
  (1702, 'Consultatio Estrategia II', 3, 22, 65, 'Renta Fija', 'Argentina', 'Flexible', NULL, 2, '2025-08-18', 1, '1708', 'El objetivo primario de la administración del Fondo es procurar la apreciación del valor del patrimonio del Fondo.', 2),
