  (565, 'Consultatio Gestión X', 5, 22, 65, 'Renta Mixta', 'Argentina', 'Mediano Plazo', NULL, 1, '2017-09-05', 1, '705', 'Consultatio Gestión X es un fondo que combina la inversión en renta fija y renta mixta con un horizonte de inversión de mediano plazo. Está nominado en pesos para las suscripciones, rescates y valuación de la cartera de inversiones. El fondo tiene una duración de hasta tres años. El objetivo del fondo es invertir en renta fija soberana, provincial y corporativa maximizando el retorno total con niveles moderados de volatilidad.', 1),
  (1262, 'Consultatio Gestión XII Pesos', 3, 22, 65, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 1, '2021-08-05', 1, '1069', 'Preservar el capital administrando una cartera de renta fija de corto y mediano plazo.', 1),
  (1202, 'Consultatio Gestion Xl Dolar', 3, 22, 65, 'Renta Fija', 'Argentina', 'Mediano Plazo', NULL, 180, '2020-05-12', 1, '1070', 'Sin datos', 1),
