  (370, 'Delta Acciones', 2, 321, 65, 'Renta Variable', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-14', 1, '505', 'El fondo tiene como objetivo de inversión lograr rentabilidades superiores a su índice de referencia, el Merval 25.', 1),
  (371, 'Delta Ahorro', 3, 321, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2005-07-11', 1, '506', 'El fondo tiene como objetivo obtener una renta en pesos superior a las tasas promedio del mercado mayorista, optimizando la relación rentabilidad/disponibilidad.', 1),
  (473, 'Delta Ahorro Plus', 3, 321, 65, 'Renta Fija', 'Argentina', 'Corto Plazo', NULL, 1, '2015-08-07', 1, '606', 'El Fondo tiene como objetivo obtener una renta en pesos superior a las tasas promedio a plazo fijo a 30 días del mercado mayorista (BADLAR).', 1),
  (572, 'Delta Crecimiento Infraestructura', 8, 321, 65, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-14', 1, '722', 'El fondo tiene como objetivo la apreciación del capital mediante la conformación de una cartera de inversiones compuesta principalmente por activos de renta fija destinados al financiamiento de proyectos productivos de economías regionales e infraestructura de la República Argentina.', 1),
  (1553, 'Delta Dólares', 4, 321, 65, 'Plazo Fijo', 'Argentina', 'Corto Plazo', NULL, 2, '2024-09-04', 1, '1567', 'Sin datos', 0),
  (452, 'Delta Empresas Argentinas Pymes', 6, 321, 65, 'Renta Mixta', 'Argentina', 'Largo Plazo', NULL, 1, '2017-09-14', 1, '589', 'El Objetivo del Fondo es invertir al menos un 75% del portafolio de inversiones en compañías argentinas de mediana y baja capitalización bursátil, incluidas las denominadas PYMEs según la definición establecida por CNV (Resolución Gral. 534) y hasta un 25% en otras Empresas Argentinas de mayor tamaño.', 1),
  (469, 'Delta Federal I', 3, 321, 65, 'Renta Fija', 'Argentina', 'Flexible', NULL, 1, '2015-08-07', 1, '605', 'El Fondo tiene como objetivo buscar retornos superiores a la curva de bonos soberanos, invirtiendo principalmente en renta fija provincial, municipal o de empresas con operaciones relevantes en economías regionales, privilegiando el Análisis Fundamental de las inversiones a largo plazo.', 1),
  (492, 'Delta Gestion I', 5, 321, 65, 'Renta Mixta', 'Global', 'Flexible', NULL, 1, '2017-10-23', 1, '624', NULL, 1),
